import { createClient } from "@supabase/supabase-js"
import { readFileSync, existsSync } from "fs"
import { fileURLToPath } from "url"
import { dirname, join } from "path"

const __dir = dirname(fileURLToPath(import.meta.url))
const root  = join(__dir, "..")

// Parse an .env file, correctly stripping inline comments and quotes
function parseEnv(filePath) {
  const result = {}
  for (const raw of readFileSync(filePath, "utf8").split("\n")) {
    const line = raw.trim()
    if (!line || line.startsWith("#")) continue
    const eq = line.indexOf("=")
    if (eq === -1) continue
    const key = line.slice(0, eq).trim()
    let val   = line.slice(eq + 1)

    // Strip inline comments: anything after whitespace + '#' (unless quoted)
    const isQuoted = /^["']/.test(val.trim())
    if (!isQuoted) val = val.replace(/\s+#.*$/, "")

    // Strip surrounding quotes, then trim whitespace
    val = val.trim().replace(/^(["'])(.*)\1$/, "$2")

    if (key) result[key] = val
  }
  return result
}

const ENV_FILES = [".env.local", ".env.development.local", ".env"]
const env = { ...process.env }

for (const name of ENV_FILES) {
  const p = join(root, name)
  if (existsSync(p)) {
    Object.assign(env, parseEnv(p))
    console.log(`📄 Loaded env from ${name}`)
    break
  }
}

const SUPABASE_URL = env["NEXT_PUBLIC_SUPABASE_URL"]
const SERVICE_KEY  = env["SUPABASE_SERVICE_ROLE_KEY"]

if (!SUPABASE_URL || !SERVICE_KEY) {
  console.error("❌ Missing NEXT_PUBLIC_SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY")
  process.exit(1)
}

// Sanity-check: keys must be printable ASCII only
for (const [k, v] of [["SUPABASE_URL", SUPABASE_URL], ["SERVICE_KEY", SERVICE_KEY]]) {
  for (let i = 0; i < v.length; i++) {
    if (v.charCodeAt(i) > 127) {
      console.error(`❌ ${k} contains non-ASCII char at index ${i}: U+${v.charCodeAt(i).toString(16).toUpperCase()}`)
      console.error(`   Check your .env file for trailing comments on that line.`)
      process.exit(1)
    }
  }
}

const supabase = createClient(SUPABASE_URL, SERVICE_KEY, {
  auth: { autoRefreshToken: false, persistSession: false },
})

