async function main() {
  console.log(`\n📦 ${MEDICAMENTS.length} médicaments CNOPS 2014 prêts à importer\n`)

  const { count, error: cErr } = await supabase
    .from("medicaments")
    .select("*", { count: "exact", head: true })

  if (cErr) {
    console.error("❌ Cannot reach Supabase:", cErr.message)
    process.exit(1)
  }

  if (count > 0 && !process.argv.includes("--force")) {
    const answer = await prompt(`⚠️  Table already has ${count} rows. Clear and reimport? (y/N) `)
    if (answer.trim().toLowerCase() !== "y") {
      console.log("Aborted. Run with --force to skip this prompt.")
      process.exit(0)
    }
  }

  if (count > 0) {
    const { error: dErr } = await supabase
      .from("medicaments")
      .delete()
      .neq("id", "00000000-0000-0000-0000-000000000000")
    if (dErr) { console.error("❌ Clear failed:", dErr.message); process.exit(1) }
    console.log(`🗑  Cleared ${count} existing rows.`)
  }

  const BATCH = 200
  let inserted = 0

  for (let i = 0; i < MEDICAMENTS.length; i += BATCH) {
    const batch = MEDICAMENTS.slice(i, i + BATCH)
    const { error } = await supabase.from("medicaments").insert(batch)
    if (error) {
      console.error(`\n❌ Batch ${Math.floor(i / BATCH) + 1} failed: ${error.message}`)
      process.exit(1)
    }
    inserted += batch.length
    const pct    = Math.round((inserted / MEDICAMENTS.length) * 100)
    const filled = Math.floor(pct / 5)
    process.stdout.write(
      `\r  [${"█".repeat(filled)}${" ".repeat(20 - filled)}] ${pct}%  (${inserted}/${MEDICAMENTS.length})`
    )
  }

  console.log(`\n\n✅ Import complet — ${inserted} médicaments insérés.`)
}

function prompt(q) {
  return new Promise(resolve => {
    process.stdout.write(q)
    process.stdin.setEncoding("utf8")
    process.stdin.once("data", d => { process.stdin.pause(); resolve(d) })
  })
}

main().catch(err => { console.error("\n❌", err.message); process.exit(1) })
